#!/usr/bin/env bash
# workflow-1.sh — 民商事案件立案前评估 SOP walkthrough for 中国法律执业.
# Auto-generated by cli_writer.py. Source: research/03-workflows.md.
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
source "${SCRIPT_DIR}/../lib/common.sh"

INDUSTRY="中国法律执业"
WORKFLOW="民商事案件立案前评估"

usage() {
  cat <<EOF
workflow-1.sh — Walk through "${WORKFLOW}" SOP for ${INDUSTRY}

逐步走完这个工作流的入门 SOP, 然后做失败模式自检, 输出走查报告。

USAGE:
  ./workflow-1.sh             # interactive
  ./workflow-1.sh --dry-run
  ./workflow-1.sh --json
  ./workflow-1.sh --explain
  ./workflow-1.sh --help
EOF
}

explain() {
  cat <<'EOT'
这个 SOP 走查脚本帮你完成 "民商事案件立案前评估" 工作流。

一句话: 从客户咨询到决定是否代理 + 立案的标准流程 (案值 / 时效 / 管辖 / 证据 / 费用 风险评估)

入门 SOP 共 8 步, 失败模式自检 12 项。

相关心智模型:
  • 程序先于实体 — 时效 / 管辖 / 主体 错一个就输: 实体法 (民法典 / 刑法 / 公司法) 决定「谁对谁错」, 程序法 (民诉 / 刑诉 / 行诉) 决定「能不能进法院」. 程序错了, 实体上多对都没用.
  • 法律不是结论, 是程序 + 论证 — 「依法」≠「我说的就对」: 法律给的不是「答案」, 是「论证路径 + 证据规则 + 程序」. 同一事实下不同律师 / 不同法官可能得出不同结果, 这不是错, 是法律的本质.

来源: research/03-workflows.md.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a SOP_STEPS=(
  "**接谈记录** — 时间 / 当事人 / 纠纷概述 / 客户期望 / 是否其他律师代理过 / 是否签订风险代理. 留痕签字"
  "**案件四要素** —"
  "**法律检索** — flk.npc.gov.cn (法源) + 北大法宝 (司法解释 + 案例) + 裁判文书网 (类案)"
  "**证据评估** — 现有证据是否充分 + 待查证据可行性 + 司法鉴定 / 公证 必要性"
  "**风险评估** —"
  "**代理决策** — 接 / 不接 (接) 风险代理 vs 普通代理 vs 计时"
  "**立案策略** — 起诉状起草 + 证据材料 + 立案登记 + 缴费 + 受理"
  "**诉讼进展** — 答辩 + 举证 + 质证 + 庭审 + 判决 + 执行 (各阶段策略)"
)
declare -a FAILURE_MODES=(
  "**时效错过** — 一般 3 年 / 短期 1 年 错过, 实体上赢了形式上输"
  "**管辖错误** — 立错法院 → 移送 / 重新立案, 浪费时间 + 错失程序优势"
  "**主体不适格** — 原告 / 被告 / 第三人 错 → 案件被驳回"
  "**证据不足 + 没调查** — 客户说的 ≠ 法律事实, 没证据等于没事实"
  "**客户期望失控** — 律师讲不清「赢」的范围, 客户落差大"
  "**执行风险评估不足** — 赢了判决拿不到钱 = 客户灾难"
  "**风险代理乱用** — 部分案件法律禁止 / 客户结果坏律师还要赔"
  "**不查类案** — 资深律师必查, 新手忽略 → 策略错配"
  "**关键决策点**:"
  "接不接: 胜诉概率 + 执行风险 + 客户费用承担 综合决定"
  "风险代理 vs 普通代理: 案值大 + 客户付不起前期费 + 不属法定禁止类型"
  "调解 vs 判决: 经济性 + 时间 + 关系修复 (商事 / 家事考量不同)"
)
declare -a STEP_STATUS=()
declare -a STEP_NOTES=()
declare -a FAIL_CHECK=()

ms_section "${INDUSTRY} · ${WORKFLOW} 走查"
ms_info "逐步走完 ${#SOP_STEPS[@]} 步入门 SOP。每步可标 done / skipped / blocked。"
echo

for i in "${!SOP_STEPS[@]}"; do
  ms_section "Step $((i+1))/${#SOP_STEPS[@]}: ${SOP_STEPS[$i]}"
  ms_prompt "状态? [d=done / s=skipped / b=blocked]"
  read -r status
  STEP_STATUS+=("${status:-d}")
  case "${status:-d}" in
    s) ms_prompt "跳过原因 (一句话):"; read -r note ;;
    b) ms_prompt "blocker (一句话):"; read -r note ;;
    *) note="" ;;
  esac
  STEP_NOTES+=("$note")
done

if [[ ${#FAILURE_MODES[@]} -gt 0 ]]; then
  ms_section "失败模式自检"
  for fm in "${FAILURE_MODES[@]}"; do
    if ms_confirm "你是否避免了 — '$fm' ?"; then
      FAIL_CHECK+=("✓ $fm")
    else
      FAIL_CHECK+=("✗ $fm")
    fi
  done
fi

ms_buffer_append "# ${INDUSTRY} — ${WORKFLOW} 走查报告"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## SOP 步骤"
ms_buffer_append ""
for i in "${!SOP_STEPS[@]}"; do
  status_icon="?"
  case "${STEP_STATUS[$i]}" in
    d|D) status_icon="✓" ;;
    s|S) status_icon="↷" ;;
    b|B) status_icon="✗" ;;
  esac
  if [[ -n "${STEP_NOTES[$i]}" ]]; then
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]} — ${STEP_NOTES[$i]}"
  else
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]}"
  fi
done
ms_buffer_append ""
if [[ ${#FAIL_CHECK[@]} -gt 0 ]]; then
  ms_buffer_append "## 失败模式自检"
  ms_buffer_append ""
  for line in "${FAIL_CHECK[@]}"; do
    ms_buffer_append "- $line"
  done
  ms_buffer_append ""
fi

if [[ $JSON -eq 1 ]]; then
  ms_emit_json \
    "workflow" "${WORKFLOW}" \
    "step_count" "${#SOP_STEPS[@]}" \
    "failure_check_count" "${#FAILURE_MODES[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "workflow-1-walkthrough"
fi
